_SECRET_PATTERNS: tuple[tuple[re.Pattern[str], str], ...] = (
    (re.compile(r"\bsk-[A-Za-z0-9_-]{12,}\b"), "[REDACTED_API_KEY]"),
    (re.compile(r"(OPENAI_API_KEY\s*=\s*)([^\s]+)"), r"\1[REDACTED_API_KEY]"),
    (
        re.compile(r"(Authorization:\s*Bearer\s+)([^\s]+)", flags=re.IGNORECASE),
        r"\1[REDACTED_TOKEN]",
    ),
)

_PREDICTION_SHAPE_LABELS: tuple[str, ...] = (
    "wall",
    "dead_end",
    "corridor",
    "corner",
    "junction",
)


def redact_secrets(text: str) -> str:
    if not text:
        return text
    redacted = text
    for pattern, replacement in _SECRET_PATTERNS:
        redacted = pattern.sub(replacement, redacted)
    return redacted


class AppKernelMixin:

    def _memory_collect_log_lines_for_step_range(
        self, step_min: int, step_max: int
    ) -> list[str]:
        if step_max < step_min:
            return []
        filtered: list[str] = []
        for line in self.memory_event_log:
            match = re.match(r"step=(\d+)\s", line)
            if not match:
                continue
            step_index = int(match.group(1))
            if step_min <= step_index <= step_max:
                filtered.append(line)
        return filtered

    def _memory_collect_log_lines(self, limit: int | None = 200) -> list[str]:
        if not self.memory_event_log:
            return []
        events = list(self.memory_event_log)
        if isinstance(limit, int) and limit > 0:
            events = events[-limit:]
        return events

    def _memory_collect_run_export_payload(
        self, maze_layout_id: int
    ) -> dict[str, object]:
        run_id = int(maze_layout_id)
        action_rows = self._run_action_outcome_rows(run_id)
        prediction_rows = self._run_prediction_rows(run_id)

        step_values = [int(row[2]) for row in action_rows if len(row) > 2]
        if step_values:
            step_min = min(step_values)
            step_max = max(step_values)
        else:
            created_steps = [
                int(row[1])
                for row in prediction_rows
                if len(row) > 1 and row[1] is not None
            ]
            resolved_steps = [
                int(row[2])
                for row in prediction_rows
                if len(row) > 2 and row[2] is not None
            ]
            all_steps = created_steps + resolved_steps
            step_min = min(all_steps) if all_steps else 0
            step_max = max(all_steps) if all_steps else 0

        return {
            "run_id": run_id,
            "action_rows": action_rows,
            "prediction_rows": prediction_rows,
            "step_min": step_min,
            "step_max": step_max,
            "memory_log_lines": self._memory_collect_log_lines_for_step_range(
                step_min, step_max
            ),
        }

