    def _start_auto_goal_session(self, total_hits: int, first_moves: list[str]) -> None:
        self.goal_session_active = True
        self.goal_session_start_hits = self.targets_reached
        self.goal_session_target_hits = max(1, total_hits)
        self.auto_goal_hits_remaining = self.goal_session_target_hits
        if first_moves:
            self._apply_agent_moves(first_moves)
        else:
            fallback_moves = self._shortest_path_moves_to_target()
            if fallback_moves:
                self._apply_agent_moves(fallback_moves)

    def _continue_auto_goal_session_if_needed(self) -> None:
        completed, remaining = self._goal_session_progress()
        self.auto_goal_hits_remaining = remaining
        if not self.goal_session_active or remaining <= 0:
            return
        next_moves = self._shortest_path_moves_to_target()
        if next_moves:
            self._apply_agent_moves(next_moves)

    def _apply_agent_moves(self, moves: list[str]) -> None:
        self.pending_agent_moves.extend(moves)
        if not self.agent_move_animation_active and self.pending_agent_moves:
            self.agent_move_animation_active = True
            self._animate_next_agent_move()

    def _cell_center(self, cell: tuple[int, int]) -> tuple[float, float]:
        row, col = cell
        center_x = col * self.cell_size + (self.cell_size / 2)
        center_y = row * self.cell_size + (self.cell_size / 2)
        return center_x, center_y

    def _update_start_end_markers(self) -> None:
        if not hasattr(self, "start_marker"):
            return

        start_row, start_col = self.episode_start_player_cell
        start_x1 = start_col * self.cell_size + 2
        start_y1 = start_row * self.cell_size + 2
        start_x2 = (start_col + 1) * self.cell_size - 2
        start_y2 = (start_row + 1) * self.cell_size - 2
        self.game_canvas.coords(
            self.start_marker, start_x1, start_y1, start_x2, start_y2
        )

        sx, sy = self._cell_center(self.episode_start_player_cell)
        self.game_canvas.coords(
            self.start_label, sx - (self.cell_size * 0.28), sy - (self.cell_size * 0.28)
        )

        ex, ey = self._cell_center(self.current_target_cell)
        self.game_canvas.coords(self.end_label, ex, ey)
        self.game_canvas.tag_raise(self.target)
        self.game_canvas.tag_raise(self.end_label)
        self.game_canvas.tag_raise(self.player)

    def _clear_fov_overlay(self) -> None:
        self.game_canvas.delete("fov")

    def _clear_mental_sweep_overlay(self) -> None:
        self.game_canvas.delete("sweep")

    def _set_player_facing_from_move(self, move: str) -> None:
        if move == "UP":
            self.player_facing = "UP"
        elif move == "DOWN":
            self.player_facing = "DOWN"
        elif move == "LEFT":
            self.player_facing = "LEFT"
        elif move == "RIGHT":
            self.player_facing = "RIGHT"

    def _available_look_directions(self) -> list[str]:
        origin = self.current_player_cell
        directions: list[str] = []
        for move in ["UP", "RIGHT", "DOWN", "LEFT"]:
            nxt = self._neighbor_for_move(origin, move)
            if nxt != origin and not self._is_blocked_cell(nxt):
                directions.append(move)
        if not directions:
            if self.player_facing in {"UP", "RIGHT", "DOWN", "LEFT"}:
                return [self.player_facing]
            return ["UP"]
        return directions

    def _all_look_directions(self) -> list[str]:
        return ["UP", "RIGHT", "DOWN", "LEFT"]

    def _reverse_direction(self, direction: str) -> str:
        mapping = {
            "UP": "DOWN",
            "DOWN": "UP",
            "LEFT": "RIGHT",
            "RIGHT": "LEFT",
        }
        return str(mapping.get((direction or "").strip().upper(), ""))

    def _mv_preplan_select_look_directions(
        self,
        hints: dict[str, object] | None = None,
        *,
        acquisition_phase: bool = False,
    ) -> list[str]:
        available = self._available_look_directions()
        if len(available) <= 1:
            return available

        hint_payload = hints if isinstance(hints, dict) else {}
        facing = (self.player_facing or "").strip().upper()
        reverse_facing = self._reverse_direction(facing)

        unknown_now = 0
        frontier_now = 0
        try:
            episodic_summary = self._episodic_memory_summary()
            unknown_now = int(episodic_summary.get("unknown", 0) or 0)
            frontier_now = int(episodic_summary.get("frontier", 0) or 0)
        except Exception:  # noqa: BLE001
            unknown_now = 0
            frontier_now = 0

        no_progress_steps = int(getattr(self, "_maze_recent_no_progress_steps", 0) or 0)
        move_entropy = (
            float(self._recent_move_direction_entropy())
            if self.maze_recent_transitions
            else 2.0
        )

        budget = 1
        if unknown_now > 0 or frontier_now > 0:
            budget = 2
        if unknown_now >= 10 or frontier_now >= 3:
            budget = 3
        if no_progress_steps >= max(2, self.maze_stuck_no_progress_threshold - 1):
            budget = max(budget, 3)
        if move_entropy <= (self.loop_entropy_threshold + 0.08):
            budget = max(budget, 3)
        if acquisition_phase and (unknown_now >= 20 or frontier_now >= 5):
            budget = 4

        exit_usable = bool(hint_payload.get("exit_usable", False))
        exit_conf = float(hint_payload.get("exit_conf", 0.0) or 0.0)
        exit_pred = tuple(hint_payload.get("exit_pred_cell", (-1, -1)) or (-1, -1))
        exit_valid = (
            isinstance(exit_pred, tuple)
            and len(exit_pred) == 2
            and 0 <= int(exit_pred[0]) < self.grid_cells
            and 0 <= int(exit_pred[1]) < self.grid_cells
        )
        if (
            exit_usable
            and exit_valid
            and exit_conf >= float(self.mv_preplan_exit_min_conf)
        ):
            budget = max(budget, 2)

        budget = max(1, min(len(available), int(budget)))

        origin = self.current_player_cell
        direction_order = {"UP": 0, "RIGHT": 1, "DOWN": 2, "LEFT": 3}
        scored: list[tuple[float, str]] = []
        for move in available:
            nxt = self._neighbor_for_move(origin, move)
            unknown_neighbors = self._unknown_neighbor_count(nxt)
            frontier_distance = min(6, self._frontier_distance(nxt, max_depth=5))
            visit_count = int(self.episode_visited_cells.get(nxt, 0) or 0)

            # Prioritize directions expected to reveal new frontier evidence,
            # while suppressing repeated no-progress reversals.
            score = (unknown_neighbors * 2.4) + (max(0, 5 - frontier_distance) * 0.75)
            score -= min(6, visit_count) * 0.40

            if move == facing:
                score += 0.25
            if reverse_facing and move == reverse_facing:
                score -= 0.45
                if no_progress_steps >= max(
                    2, self.maze_stuck_no_progress_threshold - 1
                ):
                    score -= 0.45

            if (
                exit_usable
                and exit_valid
                and exit_conf >= float(self.mv_preplan_exit_min_conf)
            ):
                curr_dist = abs(int(origin[0]) - int(exit_pred[0])) + abs(
                    int(origin[1]) - int(exit_pred[1])
                )
                nxt_dist = abs(int(nxt[0]) - int(exit_pred[0])) + abs(
                    int(nxt[1]) - int(exit_pred[1])
                )
                score += (curr_dist - nxt_dist) * 0.50

            mv_bias = self._machine_vision_cellmap_candidate_bias(origin, nxt)
            if int(mv_bias.get("usable", 0) or 0) == 1:
                score += float(mv_bias.get("open_alignment_bonus", 0) or 0) * 0.03
                score -= float(mv_bias.get("blocked_risk_penalty", 0) or 0) * 0.05
                score += float(mv_bias.get("neighbor_open_bonus", 0) or 0) * 0.02
                score -= float(mv_bias.get("neighbor_blocked_penalty", 0) or 0) * 0.03

            score -= float(direction_order.get(move, 9)) * 0.0001
            scored.append((score, move))

        scored.sort(key=lambda item: item[0], reverse=True)
        selected = [move for _score, move in scored[:budget]]
        return selected if selected else available[:1]

    def _mv_preplan_ready_for_sweep(self, hints: dict[str, object]) -> tuple[bool, str]:
        if self._normalized_layout_mode() != "maze":
            return (True, "mode=non-maze")
        if not self._machine_vision_enabled():
            return (True, "bypass:mv-disabled")
        if not self.mv_preplan_sweep_enable:
            return (True, "disabled")
        if not self.machine_vision_player_localization_enable:
            return (True, "bypass:self_localization_disabled")
        if self.mv_preplan_require_exit and (
            not self.machine_vision_exit_localization_enable
        ):
            return (True, "bypass:exit_localization_disabled")
        if not bool(hints.get("enabled", False)):
            return (True, "bypass:mv_hints_disabled")

        trusted_sources = {"learned_signature", "prior_sample_context", "prior_sample"}
        self_source = str(hints.get("self_source", "none") or "none")
        self_conf = float(hints.get("self_conf", 0.0) or 0.0)
        self_error_raw = hints.get("self_error", -1)
        self_error = int(self_error_raw if self_error_raw is not None else -1)
        self_error_ready = (self_error < 0) or (
            self_error <= int(self.mv_preplan_max_self_error)
        )
        self_ready = bool(
            bool(hints.get("self_fresh", False))
            and self_source in trusted_sources
            and self_conf >= float(self.mv_preplan_self_min_conf)
            and self_error_ready
        )

        exit_ready = True
        exit_source = str(hints.get("exit_source", "none") or "none")
        exit_conf = float(hints.get("exit_conf", 0.0) or 0.0)
        if self.mv_preplan_require_exit:
            exit_ready = bool(
                bool(hints.get("exit_usable", False))
                and bool(hints.get("exit_fresh", False))
                and exit_source in trusted_sources
                and exit_conf >= float(self.mv_preplan_exit_min_conf)
            )

        status = (
            f"self_ready={1 if self_ready else 0} "
            f"exit_ready={1 if exit_ready else 0} "
            f"self_conf={round(self_conf, 3)} "
            f"exit_conf={round(exit_conf, 3)} "
            f"self_err={self_error} "
            f"self_src={self_source} self_fresh={1 if bool(hints.get('self_fresh', False)) else 0} "
            f"exit_src={exit_source} exit_fresh={1 if bool(hints.get('exit_fresh', False)) else 0} "
            f"exit_usable={1 if bool(hints.get('exit_usable', False)) else 0}"
        )
        if self_ready and exit_ready:
            return (True, f"ready {status}")
        return (False, f"wait {status}")

    def _mv_preplan_acquire_until_ready(self) -> tuple[bool, str]:
        if self._normalized_layout_mode() != "maze":
            return (True, "mode=non-maze")
        if not self._machine_vision_enabled():
            return (True, "bypass:mv-disabled")
        if not self.mv_preplan_sweep_enable:
            return (True, "disabled")

        trusted_sources = {"learned_signature", "prior_sample_context", "prior_sample"}

        def _exit_locked(local_hints: dict[str, object]) -> bool:
            if not self.mv_preplan_require_exit:
                return True
            exit_source = str(local_hints.get("exit_source", "none") or "none")
            exit_conf = float(local_hints.get("exit_conf", 0.0) or 0.0)
            return bool(
                bool(local_hints.get("exit_usable", False))
                and bool(local_hints.get("exit_fresh", False))
                and exit_source in trusted_sources
                and exit_conf >= float(self.mv_preplan_exit_min_conf)
            )

        max_sweeps = max(1, int(self.mv_preplan_acquire_max_sweeps))
        sweep_count = 0
        last_look_dirs = ""
        hints = self._machine_vision_kernel_hints()
        ready, note = self._mv_preplan_ready_for_sweep(hints)

        # Do not begin look sweeps until MV has a confident/fresh exit lock.
        if not _exit_locked(hints):
            player_row, player_col = int(self.current_player_cell[0]), int(
                self.current_player_cell[1]
            )
            # Refresh MV side-channel predictions without any directional look sweep.
            self._update_machine_vision_localization(player_row, player_col)
            self._update_machine_vision_exit_localization(player_row, player_col)
            hints = self._machine_vision_kernel_hints()
            ready, note = self._mv_preplan_ready_for_sweep(hints)
            if _exit_locked(hints):
                self._mv_preplan_no_sweep_wait_streak = 0
                if ready:
                    suffix = f" look={last_look_dirs}" if last_look_dirs else ""
                    return (True, f"{note} sweeps={sweep_count}/{max_sweeps}{suffix}")
            else:
                self._mv_preplan_no_sweep_wait_streak += 1
                if self._mv_preplan_no_sweep_wait_streak < 2:
                    suffix = f" look={last_look_dirs}" if last_look_dirs else ""
                    return (False, f"{note} sweeps={sweep_count}/{max_sweeps}{suffix}")
                # Anti-deadlock safeguard: if no-lock wait repeats, force at least
                # one sweep acquisition pass instead of idling at sweeps=0 forever.
                self._mv_preplan_no_sweep_wait_streak = 0

        while (not ready) and sweep_count < max_sweeps:
            # Decoupled acquisition phase: gather MV evidence before any move executes.
            look_directions = self._mv_preplan_select_look_directions(
                hints, acquisition_phase=True
            )
            if not look_directions:
                look_directions = self._available_look_directions()
            last_look_dirs = ",".join(look_directions)
            self._preview_look_directions_blocking(look_directions)
            sweep_count += 1
            hints = self._machine_vision_kernel_hints()
            ready, note = self._mv_preplan_ready_for_sweep(hints)
        if ready:
            self._mv_preplan_no_sweep_wait_streak = 0
        suffix = f" look={last_look_dirs}" if last_look_dirs else ""
        return (ready, f"{note} sweeps={sweep_count}/{max_sweeps}{suffix}")

    def _fov_fill_color(
        self, strength: float, vis_kind: str, corner_graze_steps: int
    ) -> str:
        # Strength-based palette gives a user-visible cue for light/vision attenuation.
        full_palette = ["#b9eec7", "#9fe5b1", "#86dd9b", "#6ed586"]
        half_palette = ["#d1f3db", "#c3efd2", "#b5ebc9", "#a7e7c0"]
        palette = half_palette if vis_kind == "half" else full_palette

        clamped = max(0.0, min(1.0, strength))
        idx = int(round(clamped * (len(palette) - 1)))
        # Corner-graze rays should appear dimmer than direct line-of-sight rays.
        idx = max(0, idx - max(0, corner_graze_steps))
        return palette[idx]

    def _pseudo3d_cell_traversable(self, row: int, col: int) -> bool:
        if row < 0 or row >= self.grid_cells or col < 0 or col >= self.grid_cells:
            return False
        return (row, col) not in self.blocked_cells

    def _pseudo3d_screen_side_vectors(
        self, facing: str
    ) -> tuple[tuple[int, int], tuple[int, int]]:
        facing_upper = (facing or "UP").strip().upper()
        if facing_upper in {"UP", "DOWN"}:
            return (0, -1), (0, 1)
        if facing_upper == "RIGHT":
            return (-1, 0), (1, 0)
        return (1, 0), (-1, 0)

    def _pseudo3d_lateral_open_run(
        self,
        row: int,
        col: int,
        vec: tuple[int, int],
        origin_row: int,
        origin_col: int,
        facing: str,
    ) -> int:
        count = 0
        max_scan = self.grid_cells
        for step in range(1, max_scan + 1):
            rr = row + (vec[0] * step)
            cc = col + (vec[1] * step)
            if not self._pseudo3d_cell_traversable(rr, cc):
                break
            if not self._is_local_cell_visible(
                origin_row, origin_col, rr, cc, facing=facing
            ):
                break
            count += 1
        return count

    def _visible_edge_opening_cells(
        self,
        player_row: int,
        player_col: int,
        facing: str,
    ) -> list[tuple[int, int, str]]:
        fv_r, fv_c = self._facing_vector_for(facing)
        if facing in {"UP", "DOWN"}:
            side_specs = [((0, -1), "LEFT"), ((0, 1), "RIGHT")]
        else:
            side_specs = [((-1, 0), "UP"), ((1, 0), "DOWN")]

        edges: list[tuple[int, int, str]] = []
        seen_edges: set[tuple[int, int, str]] = set()

        for step in range(1, self.grid_cells + 1):
            row = player_row + (fv_r * step)
            col = player_col + (fv_c * step)
            if row < 0 or row >= self.grid_cells or col < 0 or col >= self.grid_cells:
                break
            if not self._is_local_cell_visible(
                player_row, player_col, row, col, facing=facing
            ):
                break
            if self._is_blocked_cell((row, col)):
                break

            for (sv_r, sv_c), side_name in side_specs:
                side_row = row + sv_r
                side_col = col + sv_c
                side_in_bounds = (
                    0 <= side_row < self.grid_cells and 0 <= side_col < self.grid_cells
                )
                side_visible = side_in_bounds and self._is_local_cell_visible(
                    player_row, player_col, side_row, side_col, facing=facing
                )
                side_blocked = (not side_in_bounds) or self._is_blocked_cell(
                    (side_row, side_col)
                )
                edge = (row, col, side_name)
                # Record both visible lateral openings and blocked lateral boundaries.
                if side_visible or side_blocked:
                    if edge not in seen_edges:
                        seen_edges.add(edge)
                        edges.append(edge)

        return edges

    def _visible_verified_empty_opening_edges(
        self,
        player_row: int,
        player_col: int,
        facing: str,
    ) -> list[tuple[int, int, str]]:
        side_delta = {
            "UP": (-1, 0),
            "RIGHT": (0, 1),
            "DOWN": (1, 0),
            "LEFT": (0, -1),
        }
        visible: list[tuple[int, int, str]] = []
        for row, col, side in list(self.verified_empty_opening_edges):
            if side not in side_delta:
                self.verified_empty_opening_edges.discard((row, col, side))
                continue
            if row < 0 or row >= self.grid_cells or col < 0 or col >= self.grid_cells:
                self.verified_empty_opening_edges.discard((row, col, side))
                continue
            if self._is_blocked_cell((row, col)):
                self.verified_empty_opening_edges.discard((row, col, side))
                continue
            if not self._is_local_cell_visible(
                player_row, player_col, row, col, facing=facing
            ):
                continue

            dr, dc = side_delta[side]
            side_cell = (row + dr, col + dc)
            if not self._opening_cell_fully_verified_empty(side_cell):
                self.verified_empty_opening_edges.discard((row, col, side))
                continue
            visible.append((row, col, side))

        visible.sort(key=lambda item: (item[0], item[1], item[2]))
        return visible

    def _visible_loop_risk_opening_edges(
        self,
        player_row: int,
        player_col: int,
        facing: str,
    ) -> list[tuple[int, int, str]]:
        self._prune_loop_risk_opening_edges()
        visible: list[tuple[int, int, str]] = []
        for row, col, side in list(self.loop_risk_opening_edges):
            if row < 0 or row >= self.grid_cells or col < 0 or col >= self.grid_cells:
                self.loop_risk_opening_edges.discard((row, col, side))
                continue
            if self._is_blocked_cell((row, col)):
                self.loop_risk_opening_edges.discard((row, col, side))
                continue
            if not self._is_local_cell_visible(
                player_row, player_col, row, col, facing=facing
            ):
                continue
            visible.append((row, col, side))

        visible.sort(key=lambda item: (item[0], item[1], item[2]))
        return visible

    def _half_visible_triangle_points(
        self,
        player_row: int,
        player_col: int,
        x1: int,
        y1: int,
        x2: int,
        y2: int,
        row: int,
        col: int,
        strength: float = 0.0,
    ) -> list[int]:
        dr = row - player_row
        dc = col - player_col
        width = max(1, x2 - x1)
        height = max(1, y2 - y1)
        # 2D projection-style boundary slice: not fixed 45deg. Stronger cells get
        # a wider visible slice, weaker peripheral cells get a thinner slice.
        base_ratio = 0.34 + (0.36 * max(0.0, min(1.0, strength)))
        distance = math.hypot(dr, dc)
        depth_norm = min(
            1.0, max(0.0, (distance - 1.0) / max(1.0, float(self.maze_fov_depth)))
        )
        distance_taper = 1.0 - (
            max(0.0, self.maze_fov_wedge_distance_scale) * depth_norm
        )
        cut_ratio = max(0.2, min(0.82, base_ratio * distance_taper))
        cut_px_x = max(1, min(width - 1, int(round(width * cut_ratio))))
        cut_px_y = max(1, min(height - 1, int(round(height * cut_ratio))))

        if dr < 0 and dc > 0:  # up-right
            return [x1, y2, x1, y1 + cut_px_y, x1 + cut_px_x, y2]
        if dr < 0 and dc < 0:  # up-left
            return [x2, y2, x2, y1 + cut_px_y, x2 - cut_px_x, y2]
        if dr > 0 and dc > 0:  # down-right
            return [x1, y1, x1 + cut_px_x, y1, x1, y1 + cut_px_y]
        # down-left (default)
        return [x2, y1, x2 - cut_px_x, y1, x2, y1 + cut_px_y]

    def _normalized_layout_mode(self) -> str:
        mode = (self.layout_mode.get() or "grid").strip().lower()
        if mode not in {"grid", "maze"}:
            mode = "grid"
            self.layout_mode.set(mode)
        return mode

    def _normalized_maze_difficulty(self) -> str:
        difficulty = (self.maze_difficulty.get() or "medium").strip().lower()
        if difficulty not in {"easy", "medium", "hard", "very hard"}:
            difficulty = "medium"
            self.maze_difficulty.set(difficulty)
        return difficulty

    def _maze_map_id_for_generation(self, advance: bool) -> int:
        if advance:
            return max(0, int(self.layout_generation_index))
        # When advance is disabled, regenerate the active map id, not the next one.
        return max(0, int(self.layout_generation_index) - 1)

    def _maze_start_anchor_cell(self, map_id: int, difficulty: str) -> tuple[int, int]:
        diff_offset = {"easy": 10, "medium": 20, "hard": 30, "very hard": 40}.get(
            difficulty, 20
        )
        seed = self.maze_seed_base + 700_000 + (int(map_id) * 37) + diff_offset
        rng = random.Random(seed)
        return (rng.randrange(self.grid_cells), rng.randrange(self.grid_cells))

    def _maze_layout_rng(self, advance: bool = True) -> random.Random:
        mode_offset = 1000 if self._normalized_layout_mode() == "maze" else 0
        diff = self._normalized_maze_difficulty()
        diff_offset = {"easy": 10, "medium": 20, "hard": 30, "very hard": 40}.get(
            diff, 20
        )
        map_id = self._maze_map_id_for_generation(advance)
        seed = self.maze_seed_base + map_id + mode_offset + diff_offset
        if advance:
            self.layout_generation_index = map_id + 1
        return random.Random(seed)

    def _event_rng(self) -> random.Random:
        mode_offset = 1000 if self._normalized_layout_mode() == "maze" else 0
        diff = self._normalized_maze_difficulty()
        diff_offset = {"easy": 10, "medium": 20, "hard": 30, "very hard": 40}.get(
            diff, 20
        )
        seed = (
            self.maze_seed_base
            + 100_000
            + self.layout_event_index
            + mode_offset
            + diff_offset
        )
        self.layout_event_index += 1
        return random.Random(seed)

    def _current_maze_map_id(self) -> int:
        # layout_generation_index advances immediately after generation.
        return max(0, self.layout_generation_index - 1)

    def _sync_maze_start_number_to_current(self) -> None:
        self.maze_map_start_var.set(str(self._current_maze_map_id()))

    def _open_cells(self) -> list[tuple[int, int]]:
        return [
            (row, col)
            for row in range(self.grid_cells)
            for col in range(self.grid_cells)
            if (row, col) not in self.blocked_cells
        ]

    def _random_open_cell(
        self,
        rng: random.Random,
        exclude: tuple[int, int] | None = None,
    ) -> tuple[int, int]:
        open_cells = [cell for cell in self._open_cells() if cell != exclude]
        if not open_cells:
            if exclude is not None:
                return exclude
            return (0, 0)
        return rng.choice(open_cells)

    def _generate_blockers(self, protected_cell: tuple[int, int] | None = None) -> None:
        self.blocked_cells = set()
        density = min(0.42, max(0.08, self.blocker_density))
        if protected_cell is None:
            protected_cell = (
                self.current_player_cell if self.current_player_cell else (0, 0)
            )
        for row in range(self.grid_cells):
            for col in range(self.grid_cells):
                if (row, col) == protected_cell:
                    continue
                if random.random() < density:
                    self.blocked_cells.add((row, col))

    def _generate_maze_blockers(
        self,
        protected_cell: tuple[int, int] | None,
        difficulty: str,
        rng: random.Random,
    ) -> None:
        algorithm = self._maze_algorithm_for_difficulty(difficulty, rng)
        self.current_maze_algorithm = algorithm

        if algorithm == "recursive_division":
            self.blocked_cells = self._recursive_division_blockers(protected_cell, rng)
            return

        all_cells = {
            (row, col)
            for row in range(self.grid_cells)
            for col in range(self.grid_cells)
        }
        self.blocked_cells = set(all_cells)

        nodes = self._maze_node_cells()
        for node in nodes:
            self.blocked_cells.discard(node)

        if algorithm == "prim_kruskal":
            edges = self._maze_edges_prim_kruskal_variant(nodes, rng)
        elif algorithm == "aldous_broder":
            edges = self._maze_edges_aldous_broder(nodes, rng)
        else:
            edges = self._maze_edges_dfs_backtracker(nodes, rng)

        for a, b in edges:
            mid = ((a[0] + b[0]) // 2, (a[1] + b[1]) // 2)
            self.blocked_cells.discard(mid)

        # Controlled loop carving keeps mazes traversable while preserving each algorithm style.
        _, loop_chance = self._maze_profile()
        for row in range(1, self.grid_cells - 1):
            for col in range(1, self.grid_cells - 1):
                if (row, col) in self.blocked_cells and rng.random() < loop_chance:
                    self.blocked_cells.discard((row, col))

        # Collapse wide-open pockets into tighter single-cell corridors.
        self._narrow_wide_openings(difficulty, protected_cell, rng)

        if protected_cell is not None:
            self.blocked_cells.discard(protected_cell)

    def _generate_layout(
        self,
        protected_cell: tuple[int, int] | None = None,
        advance_maze_sequence: bool = True,
    ) -> None:
        self._apply_grid_profile()
        mode = self._normalized_layout_mode()
        self._reset_maze_known_map()
        if mode != "maze":
            self.current_maze_algorithm = ""
            self._clear_working_memory()
        if mode == "maze":
            difficulty = self._normalized_maze_difficulty()
            map_id = self._maze_map_id_for_generation(advance_maze_sequence)
            start_anchor = self._maze_start_anchor_cell(map_id, difficulty)
            layout_rng = self._maze_layout_rng(advance=advance_maze_sequence)
            self._generate_maze_blockers(
                start_anchor,
                difficulty,
                layout_rng,
            )
            start_anchor = self._select_start_anchor_in_largest_open_component(
                start_anchor,
                difficulty,
                layout_rng,
            )
            # Episode id should identify the current maze layout, not target respawns.
            self.current_maze_episode_id = self._current_maze_map_id()
            self.current_player_cell = start_anchor
            self._load_layout_cell_memory_snapshot()
            if hasattr(self, "player"):
                self._place_player_at_cell(start_anchor)
            return
        if protected_cell is not None:
            protected_cell = self._sanitize_cell(protected_cell)
        elif self.current_player_cell:
            protected_cell = self._sanitize_cell(self.current_player_cell)
        self._generate_blockers(protected_cell=protected_cell)

    def _carve_path_between_cells(
        self,
        start: tuple[int, int],
        target: tuple[int, int],
        rng: random.Random | None = None,
    ) -> None:
        if rng is None:
            rng = random.Random()
        if start == target:
            self.blocked_cells.discard(start)
            return

        row, col = start
        target_row, target_col = target
        self.blocked_cells.discard((row, col))
        self.blocked_cells.discard((target_row, target_col))

        while (row, col) != (target_row, target_col):
            row_delta = target_row - row
            col_delta = target_col - col

            take_row = row_delta != 0 and (col_delta == 0 or rng.random() < 0.55)
            if take_row:
                row += 1 if row_delta > 0 else -1
            else:
                col += 1 if col_delta > 0 else -1

            row = min(self.grid_cells - 1, max(0, row))
            col = min(self.grid_cells - 1, max(0, col))
            self.blocked_cells.discard((row, col))

    def _reachable_cells_from_player(self) -> set[tuple[int, int]]:
        start = (
            self.current_player_cell
            if self.current_player_cell
            else self._player_cell()
        )
        if self._is_blocked_cell(start):
            return set()
        seen = {start}
        queue: deque[tuple[int, int]] = deque([start])
        while queue:
            cell = queue.popleft()
            for move in ["UP", "DOWN", "LEFT", "RIGHT"]:
                nxt = self._neighbor_for_move(cell, move)
                if nxt == cell or nxt in seen or self._is_blocked_cell(nxt):
                    continue
                seen.add(nxt)
                queue.append(nxt)
        return seen

    def _place_player_at_cell(self, cell: tuple[int, int]) -> None:
        row, col = cell
        offset = (self.cell_size - self.player_size) / 2
        x1 = col * self.cell_size + offset
        y1 = row * self.cell_size + offset
        self.game_canvas.coords(
            self.player,
            x1,
            y1,
            x1 + self.player_size,
            y1 + self.player_size,
        )

    def _random_cell(self) -> tuple[int, int]:
        rng = self._event_rng()
        return (
            rng.randint(0, self.grid_cells - 1),
            rng.randint(0, self.grid_cells - 1),
        )

    def _detect_fast_mode_active(self) -> bool:
        if self.move_delay_ms > self.fast_mode_move_delay_ms:
            return False
        if self.look_preview_delay_ms > self.fast_mode_look_preview_delay_ms:
            return False
        if (
            self.fast_mode_disable_sleep_after_maze_completion
            and self.sleep_cycle_auto_after_maze_completion
        ):
            return False
        if (
            self.fast_mode_disable_sleep_after_log_dump
            and self.sleep_cycle_auto_after_log_dump
        ):
            return False
        if (
            self.fast_mode_disable_adaptive_progress_report
            and self.adaptive_progress_report_enable
        ):
            return False
        if (
            self.fast_mode_disable_adaptive_progress_auto_tune
            and self.adaptive_progress_auto_tune
        ):
            return False
        return True

    def _apply_fast_mode_profile(
        self, enabled: bool, *, sync_var: bool = True, persist: bool = True
    ) -> None:
        enabled_flag = bool(enabled)
        if enabled_flag:
            self.move_delay_ms = self.fast_mode_move_delay_ms
            self.look_preview_delay_ms = self.fast_mode_look_preview_delay_ms
            if self.fast_mode_disable_sleep_after_maze_completion:
                self.sleep_cycle_auto_after_maze_completion = False
            if self.fast_mode_disable_sleep_after_log_dump:
                self.sleep_cycle_auto_after_log_dump = False
            if self.fast_mode_disable_adaptive_progress_report:
                self.adaptive_progress_report_enable = False
            if self.fast_mode_disable_adaptive_progress_auto_tune:
                self.adaptive_progress_auto_tune = False
        else:
            self.move_delay_ms = self.normal_mode_move_delay_ms
            self.look_preview_delay_ms = self.normal_mode_look_preview_delay_ms
            self.sleep_cycle_auto_after_maze_completion = (
                self.normal_mode_sleep_after_maze_completion
            )
            self.sleep_cycle_auto_after_log_dump = self.normal_mode_sleep_after_log_dump
            self.adaptive_progress_report_enable = (
                self.normal_mode_adaptive_progress_report
            )
            self.adaptive_progress_auto_tune = (
                self.normal_mode_adaptive_progress_auto_tune
            )

        self.fast_mode_enabled = enabled_flag
        if sync_var and hasattr(self, "fast_mode_enabled_var"):
            if bool(self.fast_mode_enabled_var.get()) != enabled_flag:
                self.fast_mode_enabled_var.set(enabled_flag)
        if persist:
            self._save_window_geometry()

    def _challenge_prompt_text(self) -> str:
        run_length = max(
            1,
            min(
                self.max_repeat_executions,
                int(getattr(self, "challenge_mode_run_length", 25)),
            ),
        )
        maze_label = "mazes" if run_length != 1 else "maze"
        return f"solve {run_length} {maze_label}"

    def _apply_challenge_mode_profile(
        self,
        enabled: bool,
        *,
        sync_var: bool = True,
        persist: bool = True,
        randomize_on_enable: bool = True,
    ) -> None:
        enabled_flag = bool(enabled)
        was_enabled = bool(getattr(self, "challenge_mode_enabled", False))
        layout_changed = False
        difficulty_changed = False

        if enabled_flag and not was_enabled:
            self.challenge_mode_previous_difficulty = self._normalized_maze_difficulty()

        if enabled_flag:
            if self._normalized_layout_mode() != "maze":
                self.layout_mode.set("maze")
                layout_changed = True
            if (
                self.challenge_mode_force_hard_difficulty
                and self._normalized_maze_difficulty() != "hard"
            ):
                self.maze_difficulty.set("hard")
                difficulty_changed = True
        elif was_enabled and self.challenge_mode_force_hard_difficulty:
            restore_difficulty = (
                str(
                    getattr(self, "challenge_mode_previous_difficulty", "medium")
                    or "medium"
                )
                .strip()
                .lower()
            )
            if restore_difficulty not in {"easy", "medium", "hard", "very hard"}:
                restore_difficulty = "medium"
            if self._normalized_maze_difficulty() != restore_difficulty:
                self.maze_difficulty.set(restore_difficulty)
                difficulty_changed = True

        self.challenge_mode_enabled = enabled_flag
        if sync_var and hasattr(self, "challenge_mode_enabled_var"):
            if bool(self.challenge_mode_enabled_var.get()) != enabled_flag:
                self.challenge_mode_enabled_var.set(enabled_flag)

        if layout_changed or difficulty_changed:
            self._on_layout_settings_changed()

        transitioned_on = enabled_flag and not was_enabled
        if (
            transitioned_on
            and randomize_on_enable
            and self.challenge_mode_randomize_start_on_enable
            and self._normalized_layout_mode() == "maze"
        ):
            self._randomize_maze_start_number()

        self._sync_prompt_for_challenge_mode(enabled_flag)

        if persist:
            self._save_window_geometry()
